const SOUND_DATA = {
  pickUp: "data:audio/wav;base64,",
  drop: "data:audio/wav;base64,",
  correct: "data:audio/wav;base64,",
  wrong: "data:audio/wav;base64,",
  levelComplete: "data:audio/wav;base64,",
  gameOver: "data:audio/wav;base64,"
};

const audioPool = {};
let audioUnlocked = false;

function preloadAll() {
  Object.keys(SOUND_DATA).forEach(key => {
    const a = new Audio(SOUND_DATA[key]);
    a.preload = 'auto';
    a.load();
    audioPool[key] = a;
  });
}

function playSound(key) {
  if (!audioUnlocked) return;
  const base = audioPool[key];
  if (!base) return;
  const node = base.cloneNode(true);
  node.volume = 1.0;
  node.play().catch(() => {});
}

const Sounds = {
  unlockAudio() {
    if (audioUnlocked) return;
    Object.keys(audioPool).forEach(key => {
      const a = audioPool[key];
      a.play().then(() => {
        a.pause();
        a.currentTime = 0;
      }).catch(() => {});
    });
    audioUnlocked = true;
  },
  pickUp() { playSound('pickUp'); },
  drop() { playSound('drop'); },
  correct() { playSound('correct'); },
  wrong() { playSound('wrong'); },
  levelComplete() { playSound('levelComplete'); },
  gameOver() { playSound('gameOver'); }
};

preloadAll();
window.Sounds = Sounds;

['pointerdown','touchstart','click'].forEach(evt => {
  document.addEventListener(evt, function unlockOnce() {
    Sounds.unlockAudio();
  }, { once: true, passive: true });
});
